242→+/**
243→+ * Deus CLI — run Deus from the command line.
244→+ *
245→+ * Smart default:
246→+ *   npx deus-machine        Desktop → install/launch app. Server → headless.
247→+ *
248→+ * Commands:
249→+ *   deus                    Auto-detect best mode
250→+ *   deus start              Start headless server (backend + agent-server)
251→+ *   deus install            Download and install the desktop app
252→+ *   deus pair               Generate a pairing code for remote access
253→+ *   deus login              Configure AI agent authentication
254→+ *   deus status             Show server info and connected devices
255→+ */
256→+
257→+import { parseArgs } from "node:util";
258→+import { start } from "./start.js";
259→+import { installDesktop, hasDisplay, findInstalledApp, launchDesktop } from "./desktop.js";
260→+import { pair } from "./pair.js";
261→+import { runAuthSetup } from "./login.js";
262→+import { showStatus } from "./status.js";
263→+import {
264→+  animatedBanner,
265→+  banner,
266→+  c,
267→+  sym,
268→+  blank,
269→+  info,
270→+  hint,
271→+  success,
272→+  error,
273→+  warn,
274→+  gradientText,
275→+} from "./ui.js";
276→+
277→+function printHelp(version: string) {
278→+  banner(version);
279→+  console.log(`  ${c.bold("Usage:")}   deus ${c.dim("[command] [options]")}`);
280→+  blank();
281→+
282→+  console.log(`  ${c.bold("Commands:")}`);
283→+  console.log(`    ${c.cyan("(none)")}        Auto-detect: launch desktop app or start server`);
284→+  console.log(`    ${c.cyan("start")}        Start headless server ${c.dim("(backend + agent-server)")}`);
285→+  console.log(`    ${c.cyan("install")}      Download and install the desktop app`);
286→+  console.log(`    ${c.cyan("pair")}         Generate a pairing code for remote access`);
287→+  console.log(`    ${c.cyan("login")}        Configure AI agent authentication`);
288→+  console.log(`    ${c.cyan("status")}       Show server info and connected devices`);
289→+  blank();
290→+
291→+  console.log(`  ${c.bold("Options")} ${c.dim("(start):")}`);
292→+  console.log(`    ${c.cyan("--data-dir")}   Directory for database and data files`);
293→+  blank();
294→+
295→+  console.log(`  ${c.bold("Options")} ${c.dim("(install):")}`);
296→+  console.log(`    ${c.cyan("--version")}    Install a specific version ${c.dim("(default: latest)")}`);
297→+  blank();
298→+
299→+  console.log(`  ${c.bold("Examples:")}`);
300→+  console.log(`    ${c.dim("$")} deus                    ${c.dim("# auto-detect mode")}`);
301→+  console.log(`    ${c.dim("$")} deus start               ${c.dim("# run headless server")}`);
302→+  console.log(`    ${c.dim("$")} deus install              ${c.dim("# install desktop app")}`);
303→+  console.log(`    ${c.dim("$")} deus pair                 ${c.dim("# generate pairing code")}`);
304→+  console.log(`    ${c.dim("$")} deus login                ${c.dim("# set up AI agent auth")}`);
305→+  console.log(`    ${c.dim("$")} deus status               ${c.dim("# show server info")}`);
306→+  blank();
307→+
308→+  console.log(`  ${c.bold("Quick start:")}`);
309→+  console.log(`    ${c.dim("$")} npx deus-machine          ${c.dim("# just works, no install needed")}`);
310→+  blank();
311→+}
312→+
313→+async function main() {
314→+  const args = process.argv.slice(2);
315→+  const command = args[0] && !args[0].startsWith("-") ? args[0] : null;
316→+  const commandArgs = command ? args.slice(1) : args;
317→+
318→+  // Load version once
319→+  const pkg = await import("../package.json", { with: { type: "json" } });
320→+  const version = pkg.default.version;
321→+
322→+  // Version (plain output, no banner)
323→+  if (args.includes("--version") || args.includes("-v")) {
324→+    console.log(version);
325→+    process.exit(0);
326→+  }
327→+
328→+  // Help
329→+  if (command === "help" || args.includes("--help") || args.includes("-h")) {
330→+    printHelp(version);
331→+    process.exit(0);
332→+  }
333→+
334→+  // Commands that don't need the full banner
335→+  const quickCommands = ["pair", "status", "login"];
336→+  if (!command || !quickCommands.includes(command)) {
337→+    await animatedBanner(version);
338→+  }
339→+
340→+  // Resolve command
341→+  const resolvedCommand = command ?? autoDetect();
342→+
343→+  switch (resolvedCommand) {
344→+    // ── Start headless server ──────────────────────────────────────
345→+    case "start":
346→+    case "serve": { // backward compat
347→+      const { values } = parseArgs({
348→+        args: commandArgs,
349→+        options: {
350→+          "data-dir": { type: "string" },
351→+        },
352→+        strict: false,
353→+      });
354→+
355→+      await start({
356→+        dataDir: values["data-dir"] as string | undefined,
357→+      });
358→+      break;
359→+    }
