750→+function getAssetPattern(
751→+  os: string,
752→+  cpuArch: string
753→+): { matcher: (name: string) => boolean; description: string } | null {
754→+  switch (os) {
755→+    case "darwin": {
756→+      const archSuffix = cpuArch === "arm64" ? "arm64" : "x64";
757→+      return {
758→+        matcher: (name) => name.endsWith(".dmg") && name.includes(archSuffix),
759→+        description: `macOS DMG (${archSuffix})`,
760→+      };
761→+    }
762→+    case "win32":
763→+      return {
764→+        matcher: (name) => name.endsWith(".exe") && !name.includes("blockmap"),
765→+        description: "Windows installer (exe)",
766→+      };
767→+    case "linux":
768→+      return {
769→+        matcher: (name) => name.endsWith(".AppImage"),
770→+        description: "Linux AppImage",
