776→+
777→+async function fetchRelease(version: string): Promise<GithubRelease | null> {
778→+  const endpoint =
779→+    version === "latest"
780→+      ? `https://api.github.com/repos/${GITHUB_REPO}/releases/latest`
781→+      : `https://api.github.com/repos/${GITHUB_REPO}/releases/tags/${version}`;
782→+
783→+  return new Promise((resolve) => {
784→+    get(
785→+      endpoint,
786→+      { headers: { "User-Agent": "deus-cli", Accept: "application/vnd.github.v3+json" } },
787→+      (res) => {
788→+        if (res.statusCode === 302 || res.statusCode === 301) {
789→+          const loc = res.headers.location;
790→+          if (loc) {
791→+            get(loc, { headers: { "User-Agent": "deus-cli" } }, (r) => {
792→+              collectBody(r).then((b) => {
793→+                try { resolve(JSON.parse(b)); } catch { resolve(null); }
794→+              });
795→+            }).on("error", () => resolve(null));
796→+            return;
797→+          }
798→+        }
799→+        if (res.statusCode !== 200) { resolve(null); return; }
800→+        collectBody(res).then((b) => {
801→+          try { resolve(JSON.parse(b)); } catch { resolve(null); }
802→+        });
803→+      }
804→+    ).on("error", () => resolve(null));
805→+  });
806→+}
807→+
808→+function collectBody(res: IncomingMessage): Promise<string> {
809→+  return new Promise((resolve) => {
810→+    let body = "";
811→+    res.on("data", (chunk: Buffer) => (body += chunk.toString()));
812→+    res.on("end", () => resolve(body));
813→+    res.on("error", () => resolve(""));
814→+  });
815→+}
