817→+async function downloadFile(url: string, dest: string): Promise<void> {
818→+  return new Promise((resolve, reject) => {
819→+    const download = (downloadUrl: string) => {
820→+      get(downloadUrl, { headers: { "User-Agent": "deus-cli" } }, (res) => {
821→+        if (res.statusCode === 302 || res.statusCode === 301) {
822→+          const loc = res.headers.location;
823→+          if (loc) { download(loc); return; }
824→+        }
825→+
826→+        if (res.statusCode !== 200) {
827→+          reject(new Error(`Download failed with status ${res.statusCode}`));
828→+          return;
829→+        }
830→+
831→+        const totalSize = parseInt(res.headers["content-length"] || "0", 10);
832→+        let downloaded = 0;
833→+
834→+        const file = createWriteStream(dest);
835→+        res.on("data", (chunk: Buffer) => {
836→+          downloaded += chunk.length;
837→+          if (totalSize > 0) {
838→+            progressBar(downloaded, totalSize, formatBytes(downloaded) + " / " + formatBytes(totalSize));
839→+          }
840→+        });
841→+        res.pipe(file);
842→+        file.on("finish", () => {
843→+          file.close();
844→+          progressBarDone(`Downloaded ${c.dim(formatBytes(totalSize))}`);
845→+          resolve();
846→+        });
847→+        file.on("error", reject);
848→+      }).on("error", reject);
849→+    };
850→+
851→+    download(url);
852→+  });
853→+}
