856→+  if (bytes < 1024) return `${bytes} B`;
857→+  if (bytes < 1024 * 1024) return `${(bytes / 1024).toFixed(1)} KB`;
858→+  return `${(bytes / (1024 * 1024)).toFixed(1)} MB`;
859→+}
