861→+async function installForPlatform(
862→+  os: string,
863→+  filePath: string,
864→+  s: ReturnType<typeof createSpinner>
865→+): Promise<boolean> {
866→+  switch (os) {
867→+    case "darwin": {
868→+      try {
869→+        const mountOutput = execSync(`hdiutil attach "${filePath}" -nobrowse`, {
870→+          encoding: "utf-8",
871→+        });
872→+
873→+        const mountPoint = mountOutput
874→+          .split("\n")
875→+          .filter((line) => line.includes("/Volumes/"))
876→+          .map((line) => line.trim().split("\t").pop()?.trim())
877→+          .find(Boolean);
878→+
879→+        if (!mountPoint) {
880→+          s.fail("Could not mount disk image");
881→+          return false;
882→+        }
883→+
884→+        const appName = "Deus.app";
885→+        const appPath = `${mountPoint}/${appName}`;
886→+        const destPath = `/Applications/${appName}`;
887→+
888→+        if (existsSync(appPath)) {
889→+          execSync(`cp -R "${appPath}" "${destPath}"`, { stdio: "pipe" });
890→+          s.succeed(`Installed to ${c.dim("/Applications/Deus.app")}`);
891→+
892→+          launchDesktop(destPath);
893→+        } else {
894→+          s.warn("DMG mounted — drag Deus to Applications to finish");
