896→+
897→+        execSync(`hdiutil detach "${mountPoint}" -quiet`, { stdio: "pipe" });
898→+        return true;
899→+      } catch {
900→+        s.fail("Auto-install failed — opening DMG manually");
901→+        execSync(`open "${filePath}"`);
902→+        return false;
903→+      }
904→+    }
905→+
906→+    case "win32": {
907→+      s.succeed("Launching installer...");
908→+      spawn(filePath, [], { detached: true, stdio: "ignore" }).unref();
909→+      hint("Follow the on-screen instructions to complete installation.");
910→+      return true;
911→+    }
912→+
913→+    case "linux": {
914→+      execSync(`chmod +x "${filePath}"`);
915→+      const installDir = join(homedir(), ".local", "bin");
916→+      mkdirSync(installDir, { recursive: true });
917→+      const destPath = join(installDir, "Deus.AppImage");
918→+      execSync(`cp "${filePath}" "${destPath}"`);
919→+      s.succeed(`Installed to ${c.dim(destPath)}`);
920→+
921→+      launchDesktop(destPath);
922→+      return true;
923→+    }
924→+
925→+    default:
926→+      s.fail("Unsupported platform");
927→+      return false;
928→+  }
929→+}
