1849→+/**
1850→+ * Minimal QR code generator for terminal display.
1851→+ *
1852→+ * Zero dependencies. Supports byte mode, Error Correction Level L,
1853→+ * versions 1-5. Uses Unicode half-block characters for compact rendering.
1854→+ *
1855→+ * Based on the QR code specification (ISO/IEC 18004).
1856→+ */
1857→+
1858→+// ── GF(256) Arithmetic ──────────────────────────────────────────────
1859→+
1860→+// QR codes use GF(256) with primitive polynomial x^8 + x^4 + x^3 + x^2 + 1 (0x11d)
1861→+const EXP = new Uint8Array(256);
1862→+const LOG = new Uint8Array(256);
1863→+
1864→+(() => {
1865→+  let x = 1;
1866→+  for (let i = 0; i < 255; i++) {
1867→+    EXP[i] = x;
1868→+    LOG[x] = i;
1869→+    x = (x << 1) ^ (x & 0x80 ? 0x11d : 0);
1870→+  }
1871→+  EXP[255] = EXP[0];
1872→+})();
1873→+
1874→+function gfMul(a: number, b: number): number {
1875→+  if (a === 0 || b === 0) return 0;
1876→+  return EXP[(LOG[a] + LOG[b]) % 255];
1877→+}
1878→+
1879→+// ── Reed-Solomon ────────────────────────────────────────────────────
1880→+
1881→+function rsGeneratorPoly(n: number): Uint8Array {
1882→+  let g = new Uint8Array([1]);
1883→+  for (let i = 0; i < n; i++) {
1884→+    const next = new Uint8Array(g.length + 1);
1885→+    for (let j = 0; j < g.length; j++) {
1886→+      next[j] ^= g[j];
1887→+      next[j + 1] ^= gfMul(g[j], EXP[i]);
1888→+    }
1889→+    g = next;
1890→+  }
1891→+  return g;
1892→+}
1893→+
1894→+function rsEncode(data: Uint8Array, ecCount: number): Uint8Array {
1895→+  const gen = rsGeneratorPoly(ecCount);
1896→+  const result = new Uint8Array(data.length + ecCount);
1897→+  result.set(data);
1898→+
1899→+  for (let i = 0; i < data.length; i++) {
1900→+    const coef = result[i];
1901→+    if (coef !== 0) {
1902→+      for (let j = 0; j < gen.length; j++) {
1903→+        result[i + j] ^= gfMul(gen[j], coef);
1904→+      }
1905→+    }
1906→+  }
1907→+
1908→+  return result.slice(data.length);
1909→+}
1910→+
1911→+// ── Version Info ────────────────────────────────────────────────────
1912→+
1913→+// [total codewords, ec codewords per block, num blocks] for Level L
1914→+const VERSION_INFO: [number, number, number][] = [
1915→+  [0, 0, 0],       // v0 placeholder
1916→+  [26, 7, 1],      // v1: 26 total, 7 EC, 1 block → 19 data
1917→+  [44, 10, 1],     // v2: 44 total, 10 EC → 34 data
1918→+  [70, 15, 1],     // v3: 70 total, 15 EC → 55 data
1919→+  [100, 20, 1],    // v4: 100 total, 20 EC → 80 data
1920→+  [134, 26, 1],    // v5: 134 total, 26 EC → 108 data
1921→+];
1922→+
1923→+// Alignment pattern positions by version (v2+)
1924→+const ALIGNMENT_POS: number[][] = [
1925→+  [],          // v0
1926→+  [],          // v1
1927→+  [6, 18],     // v2
1928→+  [6, 22],     // v3
1929→+  [6, 26],     // v4
1930→+  [6, 30],     // v5
1931→+];
1932→+
1933→+function getVersion(dataLen: number): number {
1934→+  for (let v = 1; v <= 5; v++) {
1935→+    const [total, ec] = VERSION_INFO[v];
1936→+    const dataCapacity = total - ec;
1937→+    // Byte mode overhead: 4 bits mode + 8/16 bits length + data + 4 bits terminator
1938→+    const overhead = v <= 9 ? 2 : 3; // mode + length indicator bytes (approx)
1939→+    if (dataLen + overhead <= dataCapacity) return v;
1940→+  }
1941→+  throw new Error("Data too long for QR version 1-5");
1942→+}
1943→+
1944→+// ── Data Encoding ───────────────────────────────────────────────────
1945→+
1946→+function encodeData(data: string, version: number): Uint8Array {
1947→+  const [totalCW, ecCW] = VERSION_INFO[version];
1948→+  const dataCW = totalCW - ecCW;
1949→+  const buf = new Uint8Array(dataCW);
1950→+
1951→+  // Bit writer
1952→+  let bitPos = 0;
1953→+  function writeBits(val: number, count: number) {
1954→+    for (let i = count - 1; i >= 0; i--) {
1955→+      if (val & (1 << i)) {
1956→+        buf[bitPos >> 3] |= 0x80 >> (bitPos & 7);
1957→+      }
1958→+      bitPos++;
1959→+    }
1960→+  }
1961→+
1962→+  // Mode indicator: byte mode = 0100
1963→+  writeBits(0b0100, 4);
1964→+
1965→+  // Character count: 8 bits for v1-9
1966→+  writeBits(data.length, 8);
1967→+
1968→+  // Data bytes
1969→+  for (let i = 0; i < data.length; i++) {
1970→+    writeBits(data.charCodeAt(i) & 0xff, 8);
1971→+  }
1972→+
1973→+  // Terminator
1974→+  writeBits(0, Math.min(4, dataCW * 8 - bitPos));
1975→+
1976→+  // Pad to byte boundary
1977→+  bitPos = Math.ceil(bitPos / 8) * 8;
1978→+
1979→+  // Pad codewords (0xEC, 0x11 alternating)
1980→+  let padByte = 0;
1981→+  const padPatterns = [0xec, 0x11];
1982→+  while (bitPos < dataCW * 8) {
1983→+    writeBits(padPatterns[padByte % 2], 8);
1984→+    padByte++;
1985→+  }
1986→+
1987→+  return buf;
1988→+}
1989→+
1990→+// ── Matrix Construction ─────────────────────────────────────────────
1991→+
1992→+function createMatrix(version: number): { matrix: number[][]; size: number } {
1993→+  const size = 17 + version * 4;
1994→+  const matrix: number[][] = [];
1995→+  for (let i = 0; i < size; i++) {
1996→+    matrix.push(new Array(size).fill(-1)); // -1 = not yet set
1997→+  }
1998→+  return { matrix, size };
1999→+}

