+
+function createMatrix(version: number): { matrix: number[][]; size: number } {
+  const size = 17 + version * 4;
+  const matrix: number[][] = [];
+  for (let i = 0; i < size; i++) {
+    matrix.push(new Array(size).fill(-1)); // -1 = not yet set
+  }
+  return { matrix, size };
+}

