2738→+    httpGet<HealthResponse>(port, "/api/health"),
2739→+    httpGet<RelayStatusResponse>(port, "/api/settings/relay-status"),
2740→+    httpGet<{ devices: DeviceInfo[] }>(port, "/api/remote-auth/devices"),
2741→+    httpGet<AgentAuthResponse>(port, "/api/settings/agent-auth"),
2742→+  ]);
2743→+
2744→+  const isRunning = health !== null;
2745→+
