2761→+    if (relayStatus.serverId) {
2762→+      kv("Server ID", c.dim(relayStatus.serverId.slice(0, 12) + "..."), 14);
2763→+    }
2764→+    kv("Clients", String(relayStatus.clients), 14);
2765→+  } else {
2766→+    kv("Relay", c.dim("unknown"), 14);
2767→+  }
2768→+
2769→+  // ── Paired Devices ──
