2784→+    divider("AI Agents");
2785→+    blank();
2786→+    for (const agent of agentAuth.agents) {
2787→+      let status: string;
2788→+      if (!agent.initialized) {
2789→+        status = c.dim("not installed");
2790→+      } else if (agent.authenticated) {
