2810→+/**
2811→+ * Terminal UI primitives for the Deus CLI.
2812→+ *
2813→+ * Zero dependencies — uses raw ANSI escape codes so everything
2814→+ * bundles into a single file with esbuild. Inspired by Claude Code,
2815→+ * Vercel CLI, and create-next-app.
2816→+ */
2817→+
2818→+// ── ANSI Colors ──────────────────────────────────────────────────────
2819→+
2820→+const ESC = "\x1b[";
2821→+const RESET = `${ESC}0m`;
2822→+
2823→+// Check NO_COLOR / FORCE_COLOR env vars (respect user preference)
2824→+const noColor = !!process.env.NO_COLOR || process.argv.includes("--no-color");
2825→+
2826→+function wrap(code: string, text: string): string {
2827→+  if (noColor) return text;
2828→+  return `${ESC}${code}m${text}${RESET}`;
2829→+}
2830→+
2831→+export const c = {
2832→+  // Modifiers
2833→+  bold: (t: string) => wrap("1", t),
2834→+  dim: (t: string) => wrap("2", t),
2835→+  italic: (t: string) => wrap("3", t),
2836→+  underline: (t: string) => wrap("4", t),
2837→+
2838→+  // Colors
2839→+  red: (t: string) => wrap("31", t),
2840→+  green: (t: string) => wrap("32", t),
2841→+  yellow: (t: string) => wrap("33", t),
2842→+  blue: (t: string) => wrap("34", t),
2843→+  magenta: (t: string) => wrap("35", t),
2844→+  cyan: (t: string) => wrap("36", t),
2845→+  white: (t: string) => wrap("37", t),
2846→+  gray: (t: string) => wrap("90", t),
2847→+
2848→+  // Bright colors
2849→+  brightCyan: (t: string) => wrap("96", t),
2850→+  brightWhite: (t: string) => wrap("97", t),
2851→+
2852→+  // Backgrounds
2853→+  bgCyan: (t: string) => wrap("46", t),
2854→+  bgBlue: (t: string) => wrap("44", t),
2855→+
2856→+  // Combos
2857→+  success: (t: string) => wrap("32", t), // green
2858→+  error: (t: string) => wrap("31", t), // red
2859→+  warn: (t: string) => wrap("33", t), // yellow
2860→+  info: (t: string) => wrap("36", t), // cyan
2861→+  label: (t: string) => wrap("1;36", t), // bold cyan
2862→+};
2863→+
2864→+// True-color (24-bit) foreground
2865→+function rgb(r: number, g: number, b: number, text: string): string {
2866→+  if (noColor) return text;
2867→+  return `\x1b[38;2;${r};${g};${b}m${text}${RESET}`;
2868→+}
2869→+
2870→+// ── Symbols ──────────────────────────────────────────────────────────
2871→+
2872→+// Unicode symbols with ASCII fallbacks for limited terminals
2873→+const isUnicode = process.platform !== "win32" || !!process.env.WT_SESSION;
2874→+
2875→+export const sym = {
2876→+  tick: isUnicode ? "✓" : "√",
2877→+  cross: isUnicode ? "✗" : "×",
2878→+  dot: isUnicode ? "●" : "*",
2879→+  dash: isUnicode ? "─" : "-",
2880→+  arrow: isUnicode ? "→" : "->",
2881→+  diamond: isUnicode ? "◆" : "*",
