2960→+/** Color a logo row: block chars in main color, shadow chars in dim */
2961→+function colorLogo(
2962→+  text: string,
2963→+  block: [number, number, number],
2964→+  shadow: [number, number, number]
2965→+): string {
2966→+  let result = "";
2967→+  let buf = "";
2968→+  let cur: "b" | "s" | " " | null = null;
2969→+
2970→+  function flush() {
2971→+    if (!buf) return;
2972→+    if (cur === "b") result += rgb(block[0], block[1], block[2], buf);
2973→+    else if (cur === "s") result += rgb(shadow[0], shadow[1], shadow[2], buf);
2974→+    else result += buf;
2975→+    buf = "";
2976→+  }
2977→+
2978→+  for (const ch of text) {
2979→+    const t = ch === " " ? " " : SHADOW_CHARS.has(ch) ? "s" : "b";
2980→+    if (t !== cur) {
2981→+      flush();
2982→+      cur = t;
2983→+    }
2984→+    buf += ch;
2985→+  }
2986→+  flush();
2987→+  return result;
