3048→+
3049→+  console.log(""); // blank line before logo
3050→+
3051→+  // Print initial empty lines (placeholder for logo)
3052→+  for (let i = 0; i < LOGO_ROWS; i++) {
3053→+    out.write("\n");
3054→+  }
3055→+
3056→+  // Animate: reveal one letter at a time
3057→+  for (let letterCount = 1; letterCount <= 4; letterCount++) {
3058→+    // Move cursor up to overwrite
3059→+    out.write(`${ESC}${LOGO_ROWS}A`);
3060→+
3061→+    const frame = renderLogoFrame(letterCount);
3062→+    for (const line of frame) {
