3080→+// ── Spinner ──────────────────────────────────────────────────────────
3081→+
3082→+const SPINNER_FRAMES = isUnicode
3083→+  ? ["⠋", "⠙", "⠹", "⠸", "⠼", "⠴", "⠦", "⠧", "⠇", "⠏"]
