3086→+const SPINNER_INTERVAL = 80;
3087→+
3088→+export interface Spinner {
3089→+  /** Update the spinner text while it's running */
3090→+  update(text: string): void;
3091→+  /** Stop with a success message */
3092→+  succeed(text?: string): void;
3093→+  /** Stop with a failure message */
3094→+  fail(text?: string): void;
3095→+  /** Stop with a warning message */
3096→+  warn(text?: string): void;
3097→+  /** Stop with an info message */
3098→+  info(text?: string): void;
3099→+  /** Stop and clear the line */
3100→+  stop(): void;
