3236→+/** Apply a gradient across a text string (from → to RGB) */
3237→+export function gradientText(
3238→+  text: string,
3239→+  from: [number, number, number],
3240→+  to: [number, number, number]
3241→+): string {
3242→+  if (noColor) return text;
3243→+  let result = "";
3244→+  for (let i = 0; i < text.length; i++) {
3245→+    const t = text.length > 1 ? i / (text.length - 1) : 0;
3246→+    const r = Math.round(from[0] + (to[0] - from[0]) * t);
3247→+    const g = Math.round(from[1] + (to[1] - from[1]) * t);
3248→+    const b = Math.round(from[2] + (to[2] - from[2]) * t);
3249→+    result += rgb(r, g, b, text[i]);
3250→+  }
3251→+  return result;
