  1→/**
  2→ * Build script for @deus/cli
  3→ *
  4→ * 1. Bundle the CLI TypeScript → dist/cli.js (esbuild)
  5→ * 2. Copy pre-built bundles into bundles/ for distribution:
  6→ *    - agent-server.bundled.cjs (from apps/agent-server/dist/)
  7→ *    - server.bundled.cjs (from apps/backend/dist/)
  8→ *
  9→ * Prerequisites: run these from the monorepo root before building the CLI:
 10→ *   bun run build:agent-server
 11→ *   bun run build:backend
 12→ */
 13→
 14→import { build } from "esbuild";
 15→import { cpSync, existsSync, mkdirSync, writeFileSync, readFileSync } from "fs";
 16→import { resolve, join, dirname } from "path";
 17→import { fileURLToPath } from "url";
 18→
 19→const __filename = fileURLToPath(import.meta.url);
 20→const cliDir = dirname(__filename);
 21→const monorepoRoot = resolve(cliDir, "../..");
 22→
 23→async function main() {
 24→  console.log("Building deus-machine CLI...\n");
 25→
 26→  // Step 1: Bundle CLI TypeScript
 27→  console.log("1. Bundling CLI...");
 28→  await build({
 29→    entryPoints: [join(cliDir, "src/cli.ts")],
 30→    bundle: true,
 31→    platform: "node",
 32→    target: "node20",
 33→    format: "esm",
 34→    outfile: join(cliDir, "dist/cli.js"),
 35→    external: [
 36→      // Native modules resolved at runtime
 37→      "better-sqlite3",
 38→      "node-pty",
 39→      "ws",
 40→    ],
 41→    packages: "external",
 42→    minify: false,
 43→    sourcemap: false,
 44→    logLevel: "info",
 45→  });
 46→
 47→  // Step 2: Create bin/ entry point
 48→  console.log("\n2. Creating bin/deus.js...");
 49→  mkdirSync(join(cliDir, "bin"), { recursive: true });
 50→  writeFileSync(join(cliDir, "bin/deus.js"), `#!/usr/bin/env node\nimport "../dist/cli.js";\n`, {
 51→    mode: 0o755,
 52→  });
 53→
 54→  // Step 3: Copy bundles for distribution
 55→  console.log("\n3. Copying bundles...");
 56→  const bundlesDir = join(cliDir, "bundles");
 57→  mkdirSync(bundlesDir, { recursive: true });
 58→
 59→  const copies: { src: string; dest: string; name: string; required: boolean }[] = [
 60→    {
 61→      src: join(monorepoRoot, "apps/agent-server/dist/index.bundled.cjs"),
 62→      dest: join(bundlesDir, "agent-server.bundled.cjs"),
 63→      name: "agent-server bundle",
 64→      required: true,
 65→    },
 66→    {
 67→      src: join(monorepoRoot, "apps/backend/dist/server.bundled.cjs"),
 68→      dest: join(bundlesDir, "server.bundled.cjs"),
 69→      name: "backend bundle",
 70→      required: true,
 71→    },
 72→  ];
 73→
 74→  let hasErrors = false;
 75→  for (const copy of copies) {
 76→    if (existsSync(copy.src)) {
 77→      cpSync(copy.src, copy.dest, { recursive: true });
 78→      console.log(`   ✓ ${copy.name}`);
 79→    } else if (copy.required) {
 80→      console.error(`   ✗ ${copy.name} not found: ${copy.src}`);
 81→      hasErrors = true;
 82→    } else {
 83→      console.log(`   - ${copy.name} not found (optional, server will work without UI)`);
 84→    }
 85→  }
 86→
 87→  if (hasErrors) {
 88→    console.error("\nMissing required bundles. Run these first:");
 89→    console.error("  bun run build:agent-server");
 90→    console.error("  bun run build:backend");
 91→    // No web frontend needed — headless mode uses app.rundeus.com via relay
 92→    process.exit(1);
 93→  }
 94→
 95→  // Step 4: Generate a standalone package.json for the published CLI
 96→  console.log("\n4. Generating publish-ready package.json...");
 97→  const pkg = JSON.parse(readFileSync(join(cliDir, "package.json"), "utf-8"));
 98→  // Ensure we don't ship "private: true" or monorepo-specific fields
 99→  delete pkg.scripts;
100→  pkg.main = "dist/cli.js";
101→  pkg.type = "module";
102→  // Note: we don't overwrite — the original is fine for publishing
103→
104→  console.log("\n✓ Build complete!");
105→  console.log(`  CLI: ${join(cliDir, "dist/cli.js")}`);
106→  console.log(`  Bin: ${join(cliDir, "bin/deus.js")}`);
107→  console.log(`  Bundles: ${bundlesDir}`);
108→  console.log("\nTo test locally:");
109→  console.log("  node apps/cli/bin/deus.js start");
110→  console.log("\nTo publish:");
111→  console.log("  cd apps/cli && npm publish");
112→}
113→
114→main().catch((err) => {
115→  console.error("Build failed:", err);
116→  process.exit(1);
117→});
