  1→/**
  2→ * Headless start mode — starts agent-server and backend.
  3→ *
  4→ * No web UI is served — remote users connect through app.rundeus.com via
  5→ * the cloud relay. This keeps the headless CLI minimal.
  6→ *
  7→ * Process orchestration:
  8→ * 1. Run onboarding (first run only — API key + remote access setup)
  9→ * 2. Start agent-server → capture LISTEN_URL from stdout
 10→ * 3. Start backend with AGENT_SERVER_URL → capture [BACKEND_PORT] from stdout
 11→ * 4. Show pairing code + QR for remote access
 12→ */
 13→
 14→import { spawn, execSync, type ChildProcess } from "node:child_process";
 15→import { existsSync } from "node:fs";
 16→import { join, resolve, dirname } from "node:path";
 17→import { fileURLToPath } from "node:url";
 18→import { platform, homedir } from "node:os";
 19→import { mkdirSync } from "node:fs";
 20→import {
 21→  spinner as createSpinner,
 22→  statusLine,
 23→  c,
 24→  sym,
 25→  box,
 26→  blank,
 27→  sleep,
 28→  success,
 29→  error,
 30→  warn,
 31→  hint,
 32→  kv,
 33→  gradientText,
 34→} from "./ui.js";
 35→import { loadConfig, hasCompletedOnboarding, writeServerInfo, clearServerInfo } from "./config.js";
 36→import { runOnboarding } from "./onboarding.js";
 37→import { showPairCode } from "./pair.js";
 38→import { formatUptime } from "./lib/format.js";
 39→
 40→const __filename = fileURLToPath(import.meta.url);
 41→const __dirname = dirname(__filename);
 42→
 43→export interface StartOptions {
 44→  dataDir?: string;
 45→}
 46→
 47→interface ProcessInfo {
 48→  process: ChildProcess;
 49→  name: string;
 50→}
 51→
 52→export async function start(options: StartOptions): Promise<void> {
 53→  const { dataDir } = options;
 54→
 55→  // ── Onboarding (first run only) ────────────────────────────────────
 56→  if (!hasCompletedOnboarding()) {
 57→    await runOnboarding();
 58→    blank();
 59→  }
 60→
 61→  const config = loadConfig();
 62→
 63→  // Resolve paths to bundles
 64→  const paths = resolveBundlePaths();
 65→  if (!paths) {
 66→    error("Could not find Deus bundles.");
 67→    blank();
 68→    hint(`Run ${c.cyan("bun run build:cli")} from the monorepo root first.`);
 69→    blank();
 70→    process.exit(1);
 71→  }
 72→
 73→  // Resolve Node binary
 74→  const nodeCmd = resolveNodeBinary();
 75→
 76→  // Resolve database
 77→  const dbPath = resolveDataDir(dataDir);
 78→  kv("Database", c.dim(dbPath));
 79→  blank();
 80→
 81→  // Track child processes for cleanup
 82→  const children: ProcessInfo[] = [];
 83→  let status: ReturnType<typeof statusLine> | null = null;
 84→
 85→  let shuttingDown = false;
 86→  let exitCode = 0;
 87→  function shutdown(code = 0) {
 88→    if (shuttingDown) return; // Prevent double-shutdown from rapid Ctrl+C
 89→    shuttingDown = true;
 90→    exitCode = code;
 91→
 92→    if (status) status.stop();
 93→    blank();
 94→
 95→    const msg = gradientText("Shutting down...", [167, 139, 250], [34, 211, 238]);
 96→    console.log(`  ${msg}`);
 97→
 98→    // Send SIGTERM and wait for children to exit (up to 5s)
 99→    const exitPromises: Promise<void>[] = [];
100→    for (const child of children) {
101→      if (child.process.exitCode === null && child.process.signalCode === null) {
102→        exitPromises.push(
103→          new Promise<void>((resolve) => {
104→            child.process.once("exit", resolve);
105→            child.process.kill("SIGTERM");
106→          })
107→        );
108→      }
109→    }
110→
111→    const drainTimeout = setTimeout(() => {
112→      // Force kill after 5s if children haven't exited
113→      for (const child of children) {
114→        if (child.process.exitCode === null && child.process.signalCode === null) {
115→          child.process.kill("SIGKILL");
116→        }
117→      }
118→    }, 5000);
119→
120→    Promise.all(exitPromises).finally(() => {
121→      clearTimeout(drainTimeout);
122→      clearServerInfo();
123→      blank();
124→      const bye = gradientText("Thanks for using Deus!", [167, 139, 250], [34, 211, 238]);
125→      console.log(`  ${bye}`);
126→      blank();
127→      process.exit(exitCode);
128→    });
129→  }
130→  process.on("SIGINT", shutdown);
131→  process.on("SIGTERM", shutdown);
132→
133→  // Build extra env vars from config
134→  const extraEnv: Record<string, string> = {};
135→  if (config.auth_method === "api_key" && config.anthropic_api_key) {
136→    extraEnv.ANTHROPIC_API_KEY = config.anthropic_api_key;
137→  }
138→
139→  // ── Step 1: Agent server ─────────────────────────────────────────
140→  const s1 = createSpinner("Starting agent server...");
141→  const agentServerUrl = await startProcess({
142→    name: "agent-server",
143→    command: nodeCmd,
144→    args: [paths.agentServer],
145→    env: { DATABASE_PATH: dbPath, ...extraEnv },
146→    waitFor: /LISTEN_URL=(.+)/,
147→    children,
148→  });
149→
150→  if (!agentServerUrl) {
151→    s1.fail("Agent server failed to start");
152→    shutdown(1);
153→    return;
154→  }
155→  s1.succeed(`Agent server ${c.dim("ready")}`);
156→
157→  // ── Step 2: Backend ──────────────────────────────────────────────
158→  const s2 = createSpinner("Starting backend...");
159→  const backendPort = await startProcess({
160→    name: "backend",
161→    command: nodeCmd,
162→    args: [paths.backend],
163→    env: {
164→      AGENT_SERVER_URL: agentServerUrl,
165→      DATABASE_PATH: dbPath,
166→      PORT: "0",
167→      ...extraEnv,
168→    },
169→    waitFor: /\[BACKEND_PORT\](\d+)/,
170→    children,
171→  });
172→
173→  if (!backendPort) {
174→    s2.fail("Backend failed to start");
175→    shutdown(1);
176→    return;
177→  }
178→  s2.succeed(`Backend ${c.dim("ready")}`);
179→
180→  const port = parseInt(backendPort, 10);
181→
182→  // Write server info for `deus pair` and `deus status`
183→  writeServerInfo({
184→    pid: process.pid,
185→    backendPort: port,
186→    agentServerUrl,
187→    startedAt: new Date().toISOString(),
188→  });
189→
190→  // ── Ready ────────────────────────────────────────────────────────
191→  blank();
192→  box(
193→    [
194→      gradientText("Deus is running", [167, 139, 250], [34, 211, 238]),
195→      "",
196→      `API  ${c.dim(`http://localhost:${port}`)}`,
197→    ],
198→    { borderColor: c.cyan, width: 38 }
199→  );
200→  blank();
201→
202→  // ── Pairing code (if relay enabled) ──────────────────────────────
203→  if (config.relay_enabled) {
204→    // Give the backend a moment to connect to the relay
205→    await sleep(1500);
206→
207→    try {
208→      await showPairCode(port);
209→    } catch {
210→      blank();
211→      warn("Could not generate pairing code.");
212→      hint(`Run ${c.cyan("deus pair")} to try again once the relay connects.`);
213→      blank();
214→    }
215→  } else {
216→    blank();
217→    hint(`Remote access is disabled. Run ${c.cyan("deus login")} to re-run setup and enable it.`);
218→    blank();
219→  }
220→
221→  // ── Status line ──────────────────────────────────────────────────
222→  blank();
223→  const startedAt = new Date();
224→  status = statusLine(() => {
225→    const elapsed = formatUptime(Date.now() - startedAt.getTime());
226→    return `${c.dim(`Running for ${elapsed}`)}  ${c.dim(`${sym.bullet} Ctrl+C to stop`)}`;
227→  }, 2000);
228→
229→  // Supervise children — if either crashes after startup, tear down and exit
230→  for (const child of children) {
231→    child.process.on("exit", (code, signal) => {
232→      if (!shuttingDown) {
233→        blank();
234→        warn(
235→          `${child.name} exited unexpectedly${signal ? ` (${signal})` : code ? ` (code ${code})` : ""}`
236→        );
237→        shutdown(1);
238→      }
239→    });
240→  }
241→
242→  // Keep the process alive
243→  await new Promise(() => {});
244→}
245→
246→// ── Bundle resolution ────────────────────────────────────────────────
247→
248→function resolveBundlePaths(): {
249→  agentServer: string;
250→  backend: string;
251→} | null {
252→  const cliRoot = resolve(__dirname, "..");
253→
254→  // Bundled mode (npm package)
255→  const bundledDir = join(cliRoot, "bundles");
256→  if (existsSync(join(bundledDir, "agent-server.bundled.cjs"))) {
257→    return {
258→      agentServer: join(bundledDir, "agent-server.bundled.cjs"),
259→      backend: join(bundledDir, "server.bundled.cjs"),
260→    };
261→  }
262→
263→  // Dev mode (monorepo)
264→  const monorepoRoot = resolve(cliRoot, "../..");
265→  const agentServer = join(monorepoRoot, "apps/agent-server/dist/index.bundled.cjs");
266→  const backend = join(monorepoRoot, "apps/backend/dist/server.bundled.cjs");
267→
268→  if (existsSync(agentServer) && existsSync(backend)) {
269→    return { agentServer, backend };
270→  }
271→
272→  return null;
273→}
274→
275→// ── Data directory ───────────────────────────────────────────────────
276→
277→function resolveDataDir(customDir?: string): string {
278→  if (customDir) {
279→    mkdirSync(customDir, { recursive: true });
280→    return join(customDir, "deus.db");
281→  }
282→
283→  const os = platform();
284→  let dir: string;
285→
286→  if (os === "darwin") {
287→    dir = join(homedir(), "Library/Application Support/com.deus.app");
288→  } else if (os === "win32") {
289→    dir = join(process.env.APPDATA || join(homedir(), "AppData/Roaming"), "com.deus.app");
290→  } else {
291→    dir = join(process.env.XDG_DATA_HOME || join(homedir(), ".local/share"), "deus");
292→  }
293→
294→  mkdirSync(dir, { recursive: true });
295→  return join(dir, "deus.db");
296→}
297→
298→// ── Node binary resolution ───────────────────────────────────────────
299→
300→function resolveNodeBinary(): string {
301→  if (process.env.ELECTRON_RUN_AS_NODE === "1") return process.execPath;
302→
303→  try {
304→    const electronPath = execSync(
305→      "node -e \"try { console.log(require('electron')) } catch { process.exit(1) }\"",
306→      { encoding: "utf-8", timeout: 5000, stdio: ["pipe", "pipe", "pipe"] }
307→    ).trim();
308→
309→    if (electronPath && existsSync(electronPath)) {
310→      try {
311→        execSync(
312→          "node -e \"const D = require('better-sqlite3'); const d = new D(':memory:'); d.close()\"",
313→          { timeout: 5000, stdio: ["pipe", "pipe", "pipe"] }
314→        );
315→        return process.execPath;
316→      } catch {
317→        return electronPath;
318→      }
319→    }
320→  } catch {
321→    // ignore — fall through to default
322→  }
323→
324→  return process.execPath;
325→}
326→
327→// ── Process spawner ──────────────────────────────────────────────────
328→
329→async function startProcess(opts: {
330→  name: string;
331→  command: string;
332→  args: string[];
333→  env: Record<string, string>;
334→  waitFor: RegExp;
335→  children: ProcessInfo[];
336→  timeoutMs?: number;
337→}): Promise<string | null> {
338→  const { name, command, args, env, waitFor, children, timeoutMs = 15_000 } = opts;
339→
340→  return new Promise((resolve) => {
341→    const processEnv: Record<string, string> = {};
342→    if (command !== process.execPath && command.includes("Electron")) {
343→      processEnv.ELECTRON_RUN_AS_NODE = "1";
344→    }
345→
346→    const child = spawn(command, args, {
347→      stdio: ["ignore", "pipe", "pipe"],
348→      env: { ...process.env, ...processEnv, ...env },
349→    });
350→
351→    children.push({ process: child, name });
352→
353→    let buffer = "";
354→    let resolved = false;
355→
356→    const timeout = setTimeout(() => {
357→      if (!resolved) {
358→        resolved = true;
359→        child.kill("SIGTERM");
360→        resolve(null);
361→      }
362→    }, timeoutMs);
363→
364→    function onStdout(data: Buffer) {
365→      buffer += data.toString();
366→      const match = buffer.match(waitFor);
367→      if (match && !resolved) {
368→        resolved = true;
369→        clearTimeout(timeout);
370→        // Stop listening and release the buffer — process may run for days
371→        child.stdout?.removeListener("data", onStdout);
372→        buffer = "";
373→        resolve(match[1]);
374→      }
375→    }
376→
377→    child.stdout?.on("data", onStdout);
378→
379→    child.on("exit", () => {
380→      if (!resolved) {
381→        resolved = true;
382→        clearTimeout(timeout);
383→        resolve(null);
384→      }
385→    });
386→  });
387→}
