  1→#!/usr/bin/env node
  2→
  3→/**
  4→ * Deus CLI — run Deus from the command line.
  5→ *
  6→ * Smart default:
  7→ *   npx deus-machine        Desktop → install/launch app. Server → headless.
  8→ *
  9→ * Commands:
 10→ *   deus                    Auto-detect best mode
 11→ *   deus start              Start headless server (backend + agent-server)
 12→ *   deus install            Download and install the desktop app
 13→ *   deus pair               Generate a pairing code for remote access
 14→ *   deus login              Configure AI agent authentication
 15→ *   deus status             Show server info and connected devices
 16→ */
 17→
 18→import { parseArgs } from "node:util";
 19→import { start } from "./start.js";
 20→import { installDesktop, hasDisplay, findInstalledApp, launchDesktop } from "./desktop.js";
 21→import { pair } from "./pair.js";
 22→import { runAuthSetup } from "./login.js";
 23→import { showStatus } from "./status.js";
 24→import { animatedBanner, banner, c, blank, info, hint, success, error } from "./ui.js";
 25→
 26→function printHelp(version: string) {
 27→  banner(version);
 28→  console.log(`  ${c.bold("Usage:")}   deus ${c.dim("[command] [options]")}`);
 29→  blank();
 30→
 31→  console.log(`  ${c.bold("Commands:")}`);
 32→  console.log(`    ${c.cyan("(none)")}        Auto-detect: launch desktop app or start server`);
 33→  console.log(
 34→    `    ${c.cyan("start")}        Start headless server ${c.dim("(backend + agent-server)")}`
 35→  );
 36→  console.log(`    ${c.cyan("install")}      Download and install the desktop app`);
 37→  console.log(`    ${c.cyan("pair")}         Generate a pairing code for remote access`);
 38→  console.log(`    ${c.cyan("login")}        Configure AI agent authentication`);
 39→  console.log(`    ${c.cyan("status")}       Show server info and connected devices`);
 40→  blank();
 41→
 42→  console.log(`  ${c.bold("Options")} ${c.dim("(start):")}`);
 43→  console.log(`    ${c.cyan("--data-dir")}   Directory for database and data files`);
 44→  blank();
 45→
 46→  console.log(`  ${c.bold("Options")} ${c.dim("(install):")}`);
 47→  console.log(
 48→    `    ${c.cyan("--version")}    Install a specific version ${c.dim("(default: latest)")}`
 49→  );
 50→  blank();
 51→
 52→  console.log(`  ${c.bold("Examples:")}`);
 53→  console.log(`    ${c.dim("$")} deus                    ${c.dim("# auto-detect mode")}`);
 54→  console.log(`    ${c.dim("$")} deus start               ${c.dim("# run headless server")}`);
 55→  console.log(`    ${c.dim("$")} deus install              ${c.dim("# install desktop app")}`);
 56→  console.log(`    ${c.dim("$")} deus pair                 ${c.dim("# generate pairing code")}`);
 57→  console.log(`    ${c.dim("$")} deus login                ${c.dim("# set up AI agent auth")}`);
 58→  console.log(`    ${c.dim("$")} deus status               ${c.dim("# show server info")}`);
 59→  blank();
 60→
 61→  console.log(`  ${c.bold("Quick start:")}`);
 62→  console.log(
 63→    `    ${c.dim("$")} npx deus-machine          ${c.dim("# just works, no install needed")}`
 64→  );
 65→  blank();
 66→}
 67→
 68→async function main() {
 69→  const args = process.argv.slice(2);
 70→  const command = args[0] && !args[0].startsWith("-") ? args[0] : null;
 71→  const commandArgs = command ? args.slice(1) : args;
 72→
 73→  // Load version once
 74→  const pkg = await import("../package.json", { with: { type: "json" } });
 75→  const version = pkg.default.version;
 76→
 77→  // Version (plain output, no banner)
 78→  if (args.includes("--version") || args.includes("-v")) {
 79→    console.log(version);
 80→    process.exit(0);
 81→  }
 82→
 83→  // Help
 84→  if (command === "help" || args.includes("--help") || args.includes("-h")) {
 85→    printHelp(version);
 86→    process.exit(0);
 87→  }
 88→
 89→  // Commands that don't need the full banner
 90→  const quickCommands = ["pair", "status", "login"];
 91→  if (!command || !quickCommands.includes(command)) {
 92→    await animatedBanner(version);
 93→  }
 94→
 95→  // Resolve command
 96→  const resolvedCommand = command ?? autoDetect();
 97→
 98→  switch (resolvedCommand) {
 99→    // ── Start headless server ──────────────────────────────────────
100→    case "start":
101→    case "serve": {
102→      // backward compat
103→      const { values } = parseArgs({
104→        args: commandArgs,
105→        options: {
106→          "data-dir": { type: "string" },
107→        },
108→        strict: false,
109→      });
110→
111→      await start({
112→        dataDir: values["data-dir"] as string | undefined,
113→      });
114→      break;
115→    }
116→
117→    // ── Install desktop app ────────────────────────────────────────
118→    case "install":
119→    case "desktop": {
120→      // backward compat
121→      // Check if already installed — just launch
122→      const installedPath = findInstalledApp();
123→      if (installedPath) {
124→        success(`Deus is installed at ${c.dim(installedPath)}`);
125→        blank();
126→        launchDesktop(installedPath);
127→        success("Launching Deus...");
128→        blank();
129→        return;
130→      }
131→
132→      const { values } = parseArgs({
133→        args: commandArgs,
134→        options: {
135→          version: { type: "string", default: "latest" },
